import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav className="bg-blue-700 text-white p-4 flex justify-between items-center shadow-md">
      <Link to="/" className="text-2xl font-bold tracking-tight">
        MyRestaurant
      </Link>
      <div className="flex items-center gap-4">
        {user ? (
          <>
            <Link to="/admin" className="hover:underline">Dashboard</Link>
            <Link to="/admin/tables" className="hover:underline">Tables</Link>
            <Link to="/profile" className="hover:underline">Profile</Link>
            <button
              onClick={handleLogout}
              className="bg-red-500 px-4 py-2 rounded hover:bg-red-700 transition"
            >
              Logout
            </button>
          </>
        ) : (
          <>
            <Link to="/" className="hover:underline">Book a Table</Link>
            <Link to="/my-reservations" className="hover:underline">My Reservations</Link>
            <Link to="/login" className="hover:underline">Admin Login</Link>
          </>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
